+function toolText(msg: AgentMessage): string {
+  if (msg.role !== "toolResult") throw new Error("expected toolResult");
+  const first = msg.content.find((b) => b.type === "text");
+  if (!first || first.type !== "text") return "";
+  return first.text;
+}
+
+function findToolResult(
+  messages: AgentMessage[],
+  toolCallId: string,
+): AgentMessage {
+  const msg = messages.find(
+    (m) => m.role === "toolResult" && m.toolCallId === toolCallId,
+  );
+  if (!msg) throw new Error(`missing toolResult: ${toolCallId}`);
+  return msg;
+}
+
+function makeToolResult(params: {
+  toolCallId: string;
+  toolName: string;
+  text: string;
+}): AgentMessage {
+  return {
+    role: "toolResult",
+    toolCallId: params.toolCallId,
+    toolName: params.toolName,
+    content: [{ type: "text", text: params.text }],
+    isError: false,
+    timestamp: Date.now(),
+  };
+}
+
+function makeImageToolResult(params: {
+  toolCallId: string;
+  toolName: string;
+  text: string;
+}): AgentMessage {
+  return {
+    role: "toolResult",
+    toolCallId: params.toolCallId,
+    toolName: params.toolName,
+    content: [
+      { type: "image", data: "AA==", mimeType: "image/png" },
+      { type: "text", text: params.text },
+    ],
+    isError: false,
+    timestamp: Date.now(),
+  };
+}
+
+function makeAssistant(text: string): AgentMessage {
+  return {
+    role: "assistant",
+    content: [{ type: "text", text }],
+    api: "openai-responses",
+    provider: "openai",
+    model: "fake",
+    usage: { input: 1, output: 1, cacheRead: 0, cacheWrite: 0, total: 2 },
+    stopReason: "stop",
+    timestamp: Date.now(),
+  };
+}
+
+function makeUser(text: string): AgentMessage {
+  return { role: "user", content: text, timestamp: Date.now() };
+}
